    Args:
        result: SearchResult object
        filters: Filter specifications to evaluate

    Returns:
        True if all filters pass, False otherwise
    """
    for field_name, filter_spec in filters.items():
        if field_name not in result.metadata:
            # Skip fields not present in metadata
            continue

        # Get actual field value from metadata
        actual_value = result.metadata[field_name]

        # Evaluate each operator in the filter spec
        for operator, expected_value in filter_spec.items():
            if operator == "==":
                if actual_value != expected_value:
                    return False
            elif operator == "!=":
                if actual_value == expected_value:
                    return False
            elif operator == "<":
                if not (actual_value < expected_value):
                    return False
            elif operator == "<=":
                if not (actual_value <= expected_value):
                    return False
            elif operator == ">":
                if not (actual_value > expected_value):
                    return False
            elif operator == ">=":
                if not (actual_value >= expected_value):
                    return False
            elif operator == "in":
                if not (actual_value in expected_value):
                    return False
            elif operator == "not_in":
                if actual_value in expected_value:
                    return False
            else:
                # Unknown operator - skip and continue
                continue

    return True
