                    # Skip invalid lines
                    continue
    except FileNotFoundError:
        # If the passage file is not found, we cannot compute coverage
        return {
            "coverage_percentage": 0.0,
            "field_coverage": {field: 0.0 for field in required_fields},
            "missing_fields": list(missing_fields_in_passages)
        }

    coverage_percentage = (covered_passages / total_passages) * 100
